return items.map(item => {
  const labels = item.json.labels?.map(l => l.id) || [];
  let userEmail = "";
  let receiveOrSend = "";

  if (labels.includes("SENT")) {
    userEmail = item.json.From.match(/<(.*)>/)?.[1] || item.json.From;
    receiveOrSend = "sent";
  } else if (labels.includes("INBOX")) {
    userEmail = item.json.To.match(/<(.*)>/)?.[1] || item.json.To;
    receiveOrSend = "received";
  }

  return {
    json: {
      content: item.json.snippet,
      to: item.json.To,
      from: item.json.From,
      receiveOrSend,
      link: `https://mail.google.com/mail/u/${userEmail}/#inbox/${item.json.id}`
    }
  };
});
